-- -----------------------------------------------------
-- procedure sp_generar_numero_ticket
-- -----------------------------------------------------

USE `db_sgi_emch`;
DROP procedure IF EXISTS `db_sgi_emch`.`sp_generar_numero_ticket`;

DELIMITER $$
USE `db_sgi_emch`$$
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_generar_numero_ticket`(OUT p_numero VARCHAR(20))
BEGIN
  DECLARE v_anio_mes CHAR(6);
  DECLARE v_secuencia INT;

  SET v_anio_mes = DATE_FORMAT(NOW(), '%Y%m');

  SELECT COALESCE(MAX(
    CAST(SUBSTRING(numero_ticket, 12) AS UNSIGNED)
  ), 0) + 1
  INTO v_secuencia
  FROM ticket
  WHERE numero_ticket LIKE CONCAT('TKT-', v_anio_mes, '-%');

  SET p_numero = CONCAT('TKT-', v_anio_mes, '-', LPAD(v_secuencia, 4, '0'));
END$$

DELIMITER ;

-- -----------------------------------------------------
-- procedure sp_verificar_stock_critico
-- -----------------------------------------------------

USE `db_sgi_emch`;
DROP procedure IF EXISTS `db_sgi_emch`.`sp_verificar_stock_critico`;

DELIMITER $$
USE `db_sgi_emch`$$
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_verificar_stock_critico`(IN p_id_tipo INT)
BEGIN
  DECLARE v_total       INT;
  DECLARE v_operativo   INT;
  DECLARE v_umbral      TINYINT;
  DECLARE v_pct_actual  DECIMAL(5,2);
  DECLARE v_nombre_tipo VARCHAR(50);

  SELECT
    te.nombre_tipo,
    COUNT(e.id_equipo),
    SUM(e.estado <> 'DADO_DE_BAJA'),
    cs.umbral_pct
  INTO v_nombre_tipo, v_total, v_operativo, v_umbral
  FROM tipo_equipo te
  LEFT JOIN equipo e      ON te.id_tipo = e.id_tipo
  LEFT JOIN config_stock cs ON te.id_tipo = cs.id_tipo
  WHERE te.id_tipo = p_id_tipo
  GROUP BY te.id_tipo, te.nombre_tipo, cs.umbral_pct;

  SET v_pct_actual = ROUND(v_operativo * 100.0 / NULLIF(v_total, 0), 1);

  -- Si el stock está por debajo del umbral, notificar a todos los admins y jefe DTIC
  IF v_pct_actual < v_umbral THEN
    INSERT INTO notificacion (id_usuario, tipo_notif, titulo, mensaje, url_accion)
    SELECT
      u.id_usuario,
      'STOCK_CRITICO',
      CONCAT('⚠️ Stock crítico: ', v_nombre_tipo),
      CONCAT(
        'El stock operativo de ', v_nombre_tipo,
        ' está en ', v_pct_actual, '% (',
        v_operativo, ' de ', v_total,
        ' equipos). Umbral mínimo configurado: ', v_umbral, '%.'
      ),
      CONCAT('/inventario?tipo=', p_id_tipo)
    FROM usuario_sistema u
    JOIN rol r ON u.id_rol = r.id_rol
    WHERE r.nombre_rol IN ('Administrador', 'Jefe DTIC')
      AND u.activo = 1;
  END IF;
END$$

DELIMITER ;

-- -----------------------------------------------------
-- View `db_sgi_emch`.`v_dashboard_resumen`
-- -----------------------------------------------------
DROP TABLE IF EXISTS `db_sgi_emch`.`v_dashboard_resumen`;
DROP VIEW IF EXISTS `db_sgi_emch`.`v_dashboard_resumen` ;
USE `db_sgi_emch`;
CREATE  OR REPLACE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `db_sgi_emch`.`v_dashboard_resumen` AS select `te`.`nombre_tipo` AS `nombre_tipo`,count(0) AS `total`,sum((`e`.`estado` = 'ASIGNADO')) AS `asignados`,sum((`e`.`estado` = 'EN_BODEGA')) AS `en_bodega`,sum((`e`.`estado` = 'EN_REPARACION')) AS `en_reparacion`,sum((`e`.`estado` = 'DADO_DE_BAJA')) AS `dados_de_baja`,sum((`e`.`estado` <> 'DADO_DE_BAJA')) AS `stock_operativo`,`cs`.`umbral_pct` AS `umbral_stock_pct`,round(((sum((`e`.`estado` <> 'DADO_DE_BAJA')) * 100.0) / nullif(count(0),0)),1) AS `pct_operativo`,sum(((timestampdiff(YEAR,`e`.`fecha_adquisicion`,curdate()) >= 5) and (`e`.`estado` <> 'DADO_DE_BAJA'))) AS `equipos_mayores_5_anios` from ((`db_sgi_emch`.`equipo` `e` join `db_sgi_emch`.`tipo_equipo` `te` on((`e`.`id_tipo` = `te`.`id_tipo`))) left join `db_sgi_emch`.`config_stock` `cs` on((`cs`.`id_tipo` = `te`.`id_tipo`))) group by `te`.`id_tipo`,`te`.`nombre_tipo`,`cs`.`umbral_pct`;

-- -----------------------------------------------------
-- View `db_sgi_emch`.`v_inventario_completo`
-- -----------------------------------------------------
DROP TABLE IF EXISTS `db_sgi_emch`.`v_inventario_completo`;
DROP VIEW IF EXISTS `db_sgi_emch`.`v_inventario_completo` ;
USE `db_sgi_emch`;
CREATE  OR REPLACE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `db_sgi_emch`.`v_inventario_completo` AS select `e`.`id_equipo` AS `id_equipo`,`e`.`codigo_ejercito` AS `codigo_ejercito`,`te`.`nombre_tipo` AS `tipo`,`ma`.`nombre_marca` AS `marca`,`me`.`nombre_modelo` AS `modelo`,`a`.`codigo_area` AS `codigo_area`,`a`.`nombre_area` AS `area`,`so`.`nombre_so` AS `nombre_so`,`so`.`version_so` AS `version_so`,`e`.`numero_serie` AS `numero_serie`,`e`.`nombre_responsable` AS `nombre_responsable`,`e`.`mac_address` AS `mac_address`,`e`.`ip_address` AS `ip_address`,`e`.`tipo_red` AS `tipo_red`,`e`.`estado` AS `estado`,`e`.`fecha_adquisicion` AS `fecha_adquisicion`,timestampdiff(YEAR,`e`.`fecha_adquisicion`,curdate()) AS `anios_antiguedad`,`e`.`fecha_registro` AS `fecha_registro`,`e`.`fecha_baja` AS `fecha_baja`,`e`.`observaciones` AS `observaciones`,`et`.`procesador` AS `procesador`,`et`.`nucleos` AS `nucleos`,`et`.`hilos` AS `hilos`,`et`.`ram_total_gb` AS `ram_total_gb`,`et`.`ram_marca` AS `ram_marca`,`et`.`ram_velocidad_mhz` AS `ram_velocidad_mhz`,`et`.`disco_capacidad_gb` AS `disco_capacidad_gb`,`et`.`disco_usado_gb` AS `disco_usado_gb`,`et`.`disco_libre_gb` AS `disco_libre_gb`,round(((`et`.`disco_usado_gb` / nullif(`et`.`disco_capacidad_gb`,0)) * 100),1) AS `disco_uso_pct`,`et`.`gpu_marca` AS `gpu_marca`,`et`.`gpu_modelo` AS `gpu_modelo`,`et`.`monitor_marca` AS `monitor_marca`,`et`.`monitor_modelo` AS `monitor_modelo` from ((((((`db_sgi_emch`.`equipo` `e` join `db_sgi_emch`.`tipo_equipo` `te` on((`e`.`id_tipo` = `te`.`id_tipo`))) join `db_sgi_emch`.`modelo_equipo` `me` on((`e`.`id_modelo` = `me`.`id_modelo`))) join `db_sgi_emch`.`marca` `ma` on((`me`.`id_marca` = `ma`.`id_marca`))) join `db_sgi_emch`.`area` `a` on((`e`.`id_area` = `a`.`id_area`))) join `db_sgi_emch`.`sistema_operativo` `so` on((`e`.`id_so` = `so`.`id_so`))) left join `db_sgi_emch`.`especificacion_tecnica` `et` on((`e`.`id_equipo` = `et`.`id_equipo`)));

-- -----------------------------------------------------
-- View `db_sgi_emch`.`v_stock_critico`
-- -----------------------------------------------------
DROP TABLE IF EXISTS `db_sgi_emch`.`v_stock_critico`;
DROP VIEW IF EXISTS `db_sgi_emch`.`v_stock_critico` ;
USE `db_sgi_emch`;
CREATE  OR REPLACE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `db_sgi_emch`.`v_stock_critico` AS select `te`.`id_tipo` AS `id_tipo`,`te`.`nombre_tipo` AS `nombre_tipo`,count(`e`.`id_equipo`) AS `total_equipos`,sum((`e`.`estado` <> 'DADO_DE_BAJA')) AS `stock_operativo`,`cs`.`umbral_pct` AS `umbral_pct`,round(((sum((`e`.`estado` <> 'DADO_DE_BAJA')) * 100.0) / nullif(count(`e`.`id_equipo`),0)),1) AS `pct_actual`,(case when (round(((sum((`e`.`estado` <> 'DADO_DE_BAJA')) * 100.0) / nullif(count(`e`.`id_equipo`),0)),1) < `cs`.`umbral_pct`) then 1 else 0 end) AS `en_alerta` from ((`db_sgi_emch`.`tipo_equipo` `te` left join `db_sgi_emch`.`equipo` `e` on((`te`.`id_tipo` = `e`.`id_tipo`))) left join `db_sgi_emch`.`config_stock` `cs` on((`te`.`id_tipo` = `cs`.`id_tipo`))) group by `te`.`id_tipo`,`te`.`nombre_tipo`,`cs`.`umbral_pct` having (`en_alerta` = 1);

-- -----------------------------------------------------
-- View `db_sgi_emch`.`v_tickets_activos`
-- -----------------------------------------------------
DROP TABLE IF EXISTS `db_sgi_emch`.`v_tickets_activos`;
DROP VIEW IF EXISTS `db_sgi_emch`.`v_tickets_activos` ;
USE `db_sgi_emch`;
CREATE  OR REPLACE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `db_sgi_emch`.`v_tickets_activos` AS select `t`.`id_ticket` AS `id_ticket`,`t`.`numero_ticket` AS `numero_ticket`,`e`.`codigo_ejercito` AS `codigo_ejercito`,`a`.`nombre_area` AS `nombre_area`,concat(`u`.`nombres`,' ',`u`.`apellidos`) AS `tecnico`,`ti`.`nombre_tipo` AS `tipo_incidente`,`t`.`titulo` AS `titulo`,`t`.`estado` AS `estado`,`t`.`prioridad` AS `prioridad`,`t`.`fecha_apertura` AS `fecha_apertura`,`ti`.`tiempo_resolucion_min` AS `sla_minutos`,timestampdiff(MINUTE,`t`.`fecha_apertura`,now()) AS `minutos_transcurridos`,(CAST(`ti`.`tiempo_resolucion_min` AS SIGNED) - timestampdiff(MINUTE,`t`.`fecha_apertura`,now())) AS `minutos_restantes_sla`,(case when (timestampdiff(MINUTE,`t`.`fecha_apertura`,now()) > `ti`.`tiempo_resolucion_min`) then 1 else 0 end) AS `sla_vencido`,`t`.`fuera_de_sla` AS `fuera_de_sla` from ((((`db_sgi_emch`.`ticket` `t` join `db_sgi_emch`.`equipo` `e` on((`t`.`id_equipo` = `e`.`id_equipo`))) join `db_sgi_emch`.`area` `a` on((`e`.`id_area` = `a`.`id_area`))) join `db_sgi_emch`.`usuario_sistema` `u` on((`t`.`id_tecnico` = `u`.`id_usuario`))) join `db_sgi_emch`.`tipo_incidente` `ti` on((`t`.`id_tipo_incidente` = `ti`.`id_tipo_incidente`))) where (`t`.`estado` in ('ABIERTO','EN_PROCESO'));
USE `db_sgi_emch`;

DELIMITER $$

USE `db_sgi_emch`$$
DROP TRIGGER IF EXISTS `db_sgi_emch`.`trg_audit_usuario_update` $$
USE `db_sgi_emch`$$
CREATE
DEFINER=`root`@`localhost`
TRIGGER `db_sgi_emch`.`trg_audit_usuario_update`
AFTER UPDATE ON `db_sgi_emch`.`usuario_sistema`
FOR EACH ROW
BEGIN
  INSERT INTO audit_log (
    id_usuario, tabla_afectada, operacion, registro_id,
    datos_anteriores, datos_nuevos, ip_origen
  ) VALUES (
    @id_usuario_activo,
    'usuario_sistema',
    'UPDATE',
    NEW.id_usuario,
    JSON_OBJECT('username', OLD.username, 'id_rol', OLD.id_rol, 'activo', OLD.activo),
    JSON_OBJECT('username', NEW.username, 'id_rol', NEW.id_rol, 'activo', NEW.activo),
    @ip_cliente
  );
END$$


