BEGIN
  INSERT INTO especificacion_tecnica (id_equipo)
  VALUES (NEW.id_equipo);
END$$


USE `db_sgi_emch`$$
DROP TRIGGER IF EXISTS `db_sgi_emch`.`trg_equipo_baja` $$
USE `db_sgi_emch`$$
CREATE
DEFINER=`root`@`localhost`
TRIGGER `db_sgi_emch`.`trg_equipo_baja`
BEFORE UPDATE ON `db_sgi_emch`.`equipo`
FOR EACH ROW
BEGIN
  IF NEW.estado = 'DADO_DE_BAJA' AND OLD.estado <> 'DADO_DE_BAJA' THEN
    SET NEW.fecha_baja = CURDATE();
  END IF;
  -- Limpiar fecha_baja si se reactiva (corrección de error)
  IF NEW.estado <> 'DADO_DE_BAJA' AND OLD.estado = 'DADO_DE_BAJA' THEN
    SET NEW.fecha_baja = NULL;
  END IF;
END$$


USE `db_sgi_emch`$$
DROP TRIGGER IF EXISTS `db_sgi_emch`.`trg_equipo_estado_update` $$
USE `db_sgi_emch`$$
CREATE
DEFINER=`root`@`localhost`
TRIGGER `db_sgi_emch`.`trg_equipo_estado_update`
AFTER UPDATE ON `db_sgi_emch`.`equipo`
FOR EACH ROW
BEGIN
  IF OLD.estado <> NEW.estado THEN
    INSERT INTO historial_estado (
      id_equipo, id_usuario, estado_anterior, estado_nuevo, motivo
    ) VALUES (
      NEW.id_equipo,
      COALESCE(@id_usuario_activo, 1),
      OLD.estado,
      NEW.estado,
      'Cambio registrado automáticamente'
    );
  END IF;
END$$


USE `db_sgi_emch`$$
DROP TRIGGER IF EXISTS `db_sgi_emch`.`trg_ticket_historial` $$
USE `db_sgi_emch`$$
CREATE
DEFINER=`root`@`localhost`
TRIGGER `db_sgi_emch`.`trg_ticket_historial`
AFTER UPDATE ON `db_sgi_emch`.`ticket`
FOR EACH ROW
BEGIN
  IF OLD.estado <> NEW.estado THEN
    INSERT INTO historial_ticket (
      id_ticket, id_usuario, estado_anterior, estado_nuevo, comentario
    ) VALUES (
      NEW.id_ticket,
      COALESCE(@id_usuario_activo, 1),
      OLD.estado,
      NEW.estado,
      'Cambio de estado automático'
    );
  END IF;
END$$


USE `db_sgi_emch`$$
DROP TRIGGER IF EXISTS `db_sgi_emch`.`trg_ticket_sla_check` $$
USE `db_sgi_emch`$$
CREATE
DEFINER=`root`@`localhost`
TRIGGER `db_sgi_emch`.`trg_ticket_sla_check`
BEFORE UPDATE ON `db_sgi_emch`.`ticket`
FOR EACH ROW
BEGIN
  DECLARE v_tiempo_sla INT;

  IF NEW.fecha_resolucion IS NOT NULL AND OLD.fecha_resolucion IS NULL THEN
    SELECT tiempo_resolucion_min INTO v_tiempo_sla
    FROM tipo_incidente
    WHERE id_tipo_incidente = NEW.id_tipo_incidente;

    IF TIMESTAMPDIFF(MINUTE, NEW.fecha_apertura, NEW.fecha_resolucion) > v_tiempo_sla THEN
      SET NEW.fuera_de_sla = 1;
    ELSE
      SET NEW.fuera_de_sla = 0;
    END IF;
  END IF;
END$$


